import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { AddstoreComponent } from './addstore/addstore.component';
import { BulkCreateStoreComponent } from './bulk-create-store/bulk-create-store.component';
import { StoreListComponent } from './store-list/store-list.component';
import { StoredetailComponent } from './storedetail/storedetail.component';

const routes: Routes = [
  {path: '', component: StoreListComponent},
  {path: 'addstore', component: AddstoreComponent},
  {path: 'storedetail/:id', component: StoredetailComponent},
  {path: 'bulkstore', component: BulkCreateStoreComponent}

];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class StoreRoutingModule { }
