import { Component, ViewChild } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from '@services/api.service';
import { AppService } from '@services/app.service';
import { environment as env } from 'environments/environment';
import { ToastrService } from 'ngx-toastr';
import { catchError, debounce, debounceTime, delay, throttleTime } from 'rxjs';


@Component({
  selector: 'app-addstore',
  templateUrl: './addstore.component.html',
  styleUrls: ['./addstore.component.scss']
})
export class AddstoreComponent {


  storeForm: FormGroup;
  addressSearchForm: FormGroup;

  pageContent: string;
  imageUrl: string;
  logoUrl: string;
  isLoading = false;

  autocompleteService: any; 
  placesService: any;
  addresses: any[] = [];

  countryList: any[]

  constructor(
    private api: ApiService, 
    private route: ActivatedRoute,
    private toastr: ToastrService,
    private fb: FormBuilder,
    private router: Router,
    private appService: AppService
  ) {

    this.autocompleteService = new window['google'].maps.places.AutocompleteService();
    this.placesService = new window['google'].maps.places.PlacesService(document.createElement('div'));

    this.countryList = this.appService.getCountryList()

    this.storeForm = this.fb.group({
      store_name: ['', [Validators.required]],
      store_ein: ['', []],
      image_url: ['', []],
      logo_url: ['', []],
      store_nick_name: ['', []],
      store_email: ['', [Validators.required]],
      store_phone: ['', [Validators.required]],
      store_phone_code:['',[Validators.required]],
      country: ['',[Validators.required]],
      state:['', [Validators.required]],
      address_name:['home' ],
      address_line_1:['', [Validators.required]],
      address_line_2:['',[]],
      landmark:[''],
      city:['', [Validators.required]],
      postal_code:['',[Validators.required]],
      longitude: ['', [Validators.required]],
      latitude: ['', [Validators.required]],
      tax_value: [0, [Validators.required, Validators.min(0), Validators.max(100)]]
    })

    this.addressSearchForm = this.fb.group({
      change_address: ['',]
    })

    this.addressSearchForm.controls.change_address.valueChanges
    .pipe(
      debounceTime(500)
    )
    .subscribe((value) => {
      console.log(value)
      this.onInputChange(value)
    })

    this.getDefaultTax()

  }

  getDefaultTax() {
    const sub = this.api.getDefaultTax().subscribe((response: any) => {
       sub.unsubscribe()
       this.storeForm.controls.tax_value.setValue(response.tax.tax_value)
    })
  }


  createStore() {
    if(!this.storeForm.valid) {
      return alert("Please fill all the necessary fields")
    }
    this.isLoading = true;
    const store = this.storeForm.value;
    const sub = this.api.createStore(
      store.store_name, store.store_ein, store.image_url, store.store_nick_name, store.store_phone, store.store_email, store.store_phone_code, store.country, store.state, store.address_name, store.address_line_1, store.address_line_2, store.landmark, store.city, store.postal_code,
      store.logo_url, store.longitude, store.latitude, store.tax_value
    )
    .pipe(
      catchError(err => {
        this.isLoading = false;
        return err;
      })
    )
    .subscribe((response: any) => {
      this.isLoading = false;
      sub.unsubscribe();
      if(response?.status >= 400) {
        this.toastr.error(response.error.message || response.message)
        return;
      }
      this.toastr.success(response.message);
      this.router.navigate(['/stores']);
    })
  }

  fileUpload(files: File[]) {
    this.isLoading = true;
    const sub = this.api.uploadSingleFile(files[0]).subscribe((response: any) => {
      sub.unsubscribe();
      this.isLoading = false;
      this.imageUrl = response.urls.orignal_url;
      this.storeForm.controls.image_url.setValue(response.urls.orignal_url)

    })
  }

  logoUpload(files: File[]) {
    this.isLoading = true;
    const sub = this.api.uploadSingleFile(files[0]).subscribe((response: any) => {
      sub.unsubscribe();
      this.isLoading = false;
      this.logoUrl = response.urls.orignal_url;
      this.storeForm.controls.logo_url.setValue(response.urls.orignal_url)
    })
  }

  onInputChange(input) {
    if (input === '') {
      this.addresses = [];
      return;
    }

    this.autocompleteService.getPlacePredictions({ input: input },(predictions, status) => {
      if (status === 'OK') {
        this.addresses = predictions;
      }
    });
  }

  changeAddress(placeId) {
    console.log(placeId)
    this.placesService.getDetails({placeId, fields: ['geometry', 'address_components'] }, (result, status) => {
      if (status === 'OK') {
        const addressLine1 = this.extractComponentValue(result, 'street_number') + ' ' +
          this.extractComponentValue(result, 'route');
        const addressLine2 = this.extractComponentValue(result, 'address_line_2');
        const city = this.extractComponentValue(result, 'locality');
        const state = this.extractComponentValue(result, 'administrative_area_level_1');
        const country = this.extractComponentValue(result, 'country');
        const zipCode = this.extractComponentValue(result, 'postal_code');

        const latitude = result.geometry?.location.lat() || 0;
        const longitude = result.geometry?.location.lng() || 0;

        this.storeForm.controls.address_line_1.setValue(addressLine1.trim())
        this.storeForm.controls.address_line_2.setValue(addressLine2.trim())
        this.storeForm.controls.city.setValue(city.trim())
        this.storeForm.controls.state.setValue(state.trim())
        this.storeForm.controls.country.setValue(country.trim())
        this.storeForm.controls.postal_code.setValue(zipCode.trim())
        this.storeForm.controls.longitude.setValue(longitude)
        this.storeForm.controls.latitude.setValue(latitude)

      } 
    })
  }

  private extractComponentValue(result, componentType: string): string {
    const component = result.address_components.find(comp =>
      comp.types.includes(componentType)
    );
    return component ? component.long_name : '';
  }

}
