import { Component } from '@angular/core';
import { FormGroup, FormBuilder, Validators } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { ApiService } from '@services/api.service';
import { environment } from 'environments/environment';
import { ToastrService } from 'ngx-toastr';
import { catchError, debounceTime, tap } from 'rxjs';

@Component({
  selector: 'app-bulk-create-store',
  templateUrl: './bulk-create-store.component.html',
  styleUrls: ['./bulk-create-store.component.scss']
})
export class BulkCreateStoreComponent {


  isLoading = false;
  env = environment


  constructor(
    private api: ApiService, 
    private route: ActivatedRoute,
    private toastr: ToastrService,
    private fb: FormBuilder,
    private router: Router
  ) {


  }

  createBulkStores(files: File[]) {
    if(!files.length) {
      return alert("Please select file")
    }
    this.isLoading = true
    const sub = this.api.createBulkStores(files[0])
    .pipe(
      catchError(err => {
      this.isLoading = false
          return err;
        })
    )
    .subscribe((response: any)=> {
      this.isLoading = false
      if(response?.status >= 400) {
        this.toastr.error(response.error.message)
        return;
      }
      sub.unsubscribe();
      this.toastr.success(response?.message);
      this.router.navigate(['/stores']);
    })
  }

  

}


