import { AfterViewInit, Component, ViewChild, OnInit } from '@angular/core';
import { FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';
import { MatPaginator } from '@angular/material/paginator';
import { MatTableDataSource } from '@angular/material/table';
import { HttpClient } from '@angular/common/http';
import { MatSort } from '@angular/material/sort';
import { catchError, delay, map, merge, of, startWith, switchMap, tap } from 'rxjs';
import { ApiService } from '@services/api.service';

@Component({
  selector: 'app-store-list',
  templateUrl: './store-list.component.html',
  styleUrls: ['./store-list.component.scss']
})
export class StoreListComponent {

  query: string = "";
  filterForm: FormGroup;
  isLoadingResults = true;

  ngOnInit(): void {

  }
  constructor(private api: ApiService, private fb: FormBuilder) {
    this.filterForm = this.fb.group({
      q: ['', []]
    })

    this.filterForm.valueChanges.pipe(
      tap(() => this.isLoadingResults = true),
      delay(1000)
    ).subscribe(() => {
      this.api.listStores(this.query, this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction).subscribe((data: any) => {
        this.isLoadingResults = false;
        if (data === null) {
          return [];
        }
  
        this.resultsLength = data.total_count;
        this.data = data.stores.map(store => {
          return {
            store_id: store.store_id,
            store_name: store.store_name,
            store_email: store.store_email,
            store_phone: store.store_phone_code + '-' + store.store_phone,
            store_owner: store.store_users.length ? store.store_users[0].user.first_name + ' ' + store.store_users[0].user.last_name : 'NA',
            is_verified: store.is_verified
          
          }
          
        });
      })
    })
  }
  displayedColumns: string[] = ['store_id', 'store_name', 'Email', 'Phone', 'Owner', 'Status', 'Action'];
  data : Store[] = [];
  resultsLength = 0;
  sortBy: string = 'store_id'

  @ViewChild(MatPaginator) paginator: MatPaginator;
  @ViewChild(MatSort) sort: MatSort;

 
  ngAfterViewInit() {
    this.sort.sortChange.subscribe(() => {
      this.paginator.pageIndex = 0
    });

    merge(this.sort.sortChange, this.paginator.page)
      .pipe(
        startWith({}),
        switchMap(() => {
          this.isLoadingResults = true;
          return this.api.listStores(this.query, this.paginator.pageIndex+1, this.paginator.pageSize, this.sort.active, this.sort.direction);
        }),
        map((data: any) => {
          this.isLoadingResults = false;
          // Flip flag to show that loading has finished.
          if (data === null) {
            return [];
          }

          this.resultsLength = data.total_count;
          return data.stores.map(store => {
            return {
            store_id: store.store_id,
            store_name: store.store_name,
            store_email: store.store_email,
            store_phone: store.store_phone_code + '-' + store.store_phone,
            store_owner: store.store_users.length ? store.store_users[0].user.first_name + ' ' + store.store_users[0].user.last_name : 'NA',
            is_verified: store.is_verified
            }
          });
        }),
      )
      .subscribe(data => this.data = data);

  }

}

export interface Store {
  store_id: string;
  store_name: string;
  store_email: string;
  store_phone: string;
  store_owner: string;
  is_verified: boolean;
}








